/**
 * Split a flat array into fixed-size chunks. The final chunk holds the
 * remainder. Used wherever a batch has a per-call cap (e.g. MCP tools that
 * accept a bounded number of IDs).
 */
export function chunk(items, size) {
    const out = [];
    for (let i = 0; i < items.length; i += size) {
        out.push(items.slice(i, i + size));
    }
    return out;
}
